   262→/**
   263→ * Format number as INR currency
   264→ */
   265→function fmtINR(amount: number): string {
   266→  const abs = Math.abs(Number(amount || 0));
   267→  const [intPart, decPart] = abs.toFixed(2).split('.');
   268→  let formatted = '';
   269→  if (intPart.length <= 3) {
   270→    formatted = intPart;
   271→  } else {
   272→    formatted = intPart.slice(-3);
   273→    let rest = intPart.slice(0, -3);
   274→    while (rest.length > 2) {
   275→      formatted = rest.slice(-2) + ',' + formatted;
   276→      rest = rest.slice(0, -2);
   277→    }
   278→    if (rest.length > 0) formatted = rest + ',' + formatted;
   279→  }
   280→  return `Rs.${formatted}.${decPart}`;
   281→}
   282→
   283→/**
   284→ * Convert amount to words — Indian number system (crore/lakh/thousand)
   285→ */
   286→function amountInWords(amount: number): string {
   287→  if (!isFinite(amount) || isNaN(amount)) return 'Amount in words: N/A';
   288→
   289→  const ONES = [
   290→    '', 'One', 'Two', 'Three', 'Four', 'Five', 'Six', 'Seven', 'Eight', 'Nine',
   291→    'Ten', 'Eleven', 'Twelve', 'Thirteen', 'Fourteen', 'Fifteen', 'Sixteen',
   292→    'Seventeen', 'Eighteen', 'Nineteen',
   293→  ];
   294→  const TENS = ['', '', 'Twenty', 'Thirty', 'Forty', 'Fifty', 'Sixty', 'Seventy', 'Eighty', 'Ninety'];
   295→
   296→  function twoDigits(n: number): string {
   297→    if (n === 0) return '';
   298→    if (n < 20) return ONES[n];
   299→    return TENS[Math.floor(n / 10)] + (n % 10 ? ' ' + ONES[n % 10] : '');
   300→  }
   301→
   302→  function threeDigits(n: number): string {
   303→    if (n === 0) return '';
   304→    if (n < 100) return twoDigits(n);
   305→    return ONES[Math.floor(n / 100)] + ' Hundred' + (n % 100 ? ' ' + twoDigits(n % 100) : '');
   306→  }
   307→
   308→  const absAmt = Math.abs(amount);
   309→  const rupees = Math.floor(absAmt);
   310→  const paise  = Math.round((absAmt - rupees) * 100);
   311→
   312→  if (rupees === 0 && paise === 0) return 'Zero Rupees Only';
   313→
   314→  const crore   = Math.floor(rupees / 10_000_000);
   315→  const lakh    = Math.floor((rupees % 10_000_000) / 100_000);
   316→  const thousand = Math.floor((rupees % 100_000) / 1_000);
   317→  const rem     = rupees % 1_000;
   318→
   319→  const parts: string[] = [];
   320→  if (crore   > 0) parts.push(threeDigits(crore)   + ' Crore');
   321→  if (lakh    > 0) parts.push(twoDigits(lakh)       + ' Lakh');
   322→  if (thousand > 0) parts.push(twoDigits(thousand)  + ' Thousand');
   323→  if (rem     > 0) parts.push(threeDigits(rem));
   324→
   325→  const prefix = amount < 0 ? 'Minus ' : '';
   326→  let result = prefix + 'Rupees ' + parts.join(' ') + ' Only';
   327→  if (paise > 0) result += ` and ${twoDigits(paise)} Paise`;
   328→  return result;
   329→}

