     1→/**
     2→ * partySync.ts
     3→ *
     4→ * When a party record is edited (name, address, GSTIN, site, etc.), every
     5→ * denormalized copy of that data across related Firestore collections must be
     6→ * updated so PartyDetailView still finds the records under the new name.
     7→ *
     8→ * Collections updated:
     9→ *   ledger_entries      — party_name, address, site
    10→ *   transactions        — party_name
    11→ *   misc_charges        — party_name, party_id
    12→ *   recurring_templates — party_name
    13→ *
    14→ * The update runs as a background operation after the party doc itself is
    15→ * saved.  Firestore batches are limited to 500 ops; we chunk in groups of 400.
    16→ */
    17→
    18→import {
    19→  collection,
    20→  query,
    21→  where,
    22→  getDocs,
    23→  writeBatch,
    24→  doc as fsDoc,
    25→} from 'firebase/firestore';
    26→import { db } from '../config/firebase';
    27→
    28→const BATCH_CHUNK = 400;
    29→
    30→interface UpdatedPartyFields {
    31→  name: string;
    32→  address?: string;
    33→  site?: string;
    34→  gstin?: string;
    35→  contact?: string;
    36→  state?: string;
    37→}
    38→
    39→/** Commit an array of [docRef, partialUpdate] in chunked batches. */
    40→async function flushUpdates(updates: Array<[any, Record<string, any>]>): Promise<void> {
    41→  for (let i = 0; i < updates.length; i += BATCH_CHUNK) {
    42→    const batch = writeBatch(db);
    43→    updates.slice(i, i + BATCH_CHUNK).forEach(([ref, data]) => batch.update(ref, data));
    44→    await batch.commit();
    45→  }
    46→}
    47→
    48→/**
    49→ * Cascade a party edit to all denormalized copies in related collections.
    50→ *
    51→ * @param uid          Firebase user UID
    52→ * @param partyId      Firestore document ID of the party
    53→ * @param oldName      The party name BEFORE the edit (used to query existing records)
    54→ * @param updated      The new field values from the edited party form
    55→ * @returns            Total number of sub-documents updated
    56→ */
    57→export async function syncPartyToRecords(
    58→  uid: string,
    59→  partyId: string,
    60→  oldName: string,
    61→  updated: UpdatedPartyFields,
    62→): Promise<number> {
    63→  const newName = updated.name;
    64→  let totalUpdated = 0;
    65→
    66→  // ── 1. ledger_entries ────────────────────────────────────────────────────
    67→  // party_name is the query key; also push address/site so future invoices
    68→  // printed from history show the current address.
    69→  try {
    70→    const col = collection(db, `users/${uid}/ledger_entries`);
    71→    const snap = await getDocs(query(col, where('party_name', '==', oldName)));
    72→    if (!snap.empty) {
    73→      const updates: Array<[any, Record<string, any>]> = snap.docs.map(d => {
    74→        const fields: Record<string, any> = { party_name: newName };
