    54→function fmtRsPdf(n: any): string {
    55→  const num = Math.abs(Number(n || 0));
    56→  const [intPart, decPart] = num.toFixed(2).split('.');
    57→  let formatted = '';
    58→  if (intPart.length <= 3) {
    59→    formatted = intPart;
    60→  } else {
    61→    formatted = intPart.slice(-3);
    62→    let rest = intPart.slice(0, -3);
    63→    while (rest.length > 2) { formatted = rest.slice(-2) + ',' + formatted; rest = rest.slice(0, -2); }
    64→    if (rest.length > 0) formatted = rest + ',' + formatted;
    65→  }
    66→  return `Rs.${formatted}.${decPart}`;
    67→}
