// ── Party cascade: update all denormalized copies in related collections ──
// Runs AFTER close so the UI is never blocked.
// Covers: ledger_entries, transactions, misc_charges, recurring_templates.
if (type === 'parties' && initialData?.id) {
  const oldName = (initialData.name || '').trim();
  const newName = (payload.name || '').trim();
  // Always cascade — even if only address/site/gstin changed — so
  // PartyDetailView shows current info on historical records.
  syncPartyToRecords(user.uid, initialData.id, oldName, {
    name: newName,
    address: payload.address,
    site:    payload.site,
    gstin:   payload.gstin,
    contact: payload.contact,
    state:   payload.state,
  }).then(count => {
    if (count > 0) {
      showToast(`Updated ${count} linked record${count !== 1 ? 's' : ''}`, 'info');
    }
    // Force-refresh caches so PartyDetailView immediately picks up the
    // renamed party_name across ledger entries and transactions.
    // (Firestore onSnapshot also fires, but explicit refetch avoids the
    // brief window where the detail view shows 0 records.)
    refetchLedger();
    refetchTransactions();
  }).catch(err => console.error('[partySync] cascade failed:', err));
}

