// ── 3. Final fallback: build plain-text from sections → share as .txt ────
// Works on Android (Filesystem + Share) regardless of GPU/jsPDF issues.
try {
  if (Capacitor.isNativePlatform()) {
    const lines: string[] = [data.title, '─'.repeat(44), ''];
    for (const section of data.sections) {
      if (section.type === 'text') {
        lines.push(section.content ?? '');
      } else if (section.type === 'table' && section.rows) {
        for (const row of section.rows) {
          lines.push(row.join('  |  '));
        }
        lines.push('');
      }
    }
    const content = lines.join('\n');
    const txtFileName = data.fileName.replace(/\.pdf$/i, '.txt');

    const { Filesystem, Directory } = await import('@capacitor/filesystem');
    const { Share } = await import('@capacitor/share');

    const writeResult = await Filesystem.writeFile({
      path: txtFileName,
      data: content,
      directory: Directory.Cache,
      encoding: 'utf8' as any,
    });

    let fileUri = writeResult.uri;
    if (!fileUri) {
      const uriResult = await Filesystem.getUri({ path: txtFileName, directory: Directory.Cache });
      fileUri = uriResult.uri;
    }

    await Share.share({ title: data.title, dialogTitle: data.title, files: [fileUri] });
    return true;
  }
} catch (e) {
