    31→/**
    32→ * WRITE TIMEOUT GUARD
    33→ * ─────────────────────────────────────────────────────────────────────────────
    34→ * On Android WebView under memory pressure, Firestore's persistentLocalCache
    35→ * writes to IndexedDB can hang indefinitely — the Promise never resolves AND
    36→ * never rejects. This leaves any UI that does `setLoading(true)` → `await write`
    37→ * → `setLoading(false)` frozen on "Saving…" forever.
    38→ *
    39→ * This wrapper races every write against a hard 15-second timeout. If the
    40→ * timeout fires first we reject with a structured WRITE_TIMEOUT error so the
    41→ * caller can fall back to the offline sync-queue instead of hanging the UI.
    42→ * 15 s is generous — a healthy IndexedDB write resolves in < 500 ms.
    43→ */
    44→const WRITE_TIMEOUT_MS = 15_000;
    45→
    46→function withWriteTimeout<T>(promise: Promise<T>): Promise<T> {
    47→  return Promise.race([
    48→    promise,
    49→    new Promise<T>((_, reject) =>
    50→      setTimeout(() => {
    51→        const err: any = new Error(
    52→          'Save timed out — queued for background sync.',
    53→        );
    54→        err.code = 'WRITE_TIMEOUT';
    55→        reject(err);
    56→      }, WRITE_TIMEOUT_MS),
    57→    ),
    58→  ]);
    59→}
