    61→/**
    62→ * Recursively removes undefined values from an object so Firestore never
    63→ * receives `undefined` fields (which it rejects with an error).
    64→ */
    65→function sanitizeForFirestore(obj: any): any {
    66→  if (obj === null || obj === undefined) return obj;
    67→  if (Array.isArray(obj)) return obj.map(sanitizeForFirestore);
    68→  if (typeof obj === 'object' && !(obj instanceof Date)) {
